const briefRow = $('Fetch Latest Brief').all()[0]?.json;
if (!briefRow) throw new Error('No ready brief found. Run WF06 first.');

const brief = briefRow.brief_json || {};
const channel = briefRow.channel || 'LinkedIn';

const voiceRow = $('Fetch Voice Rules').all()[0]?.json || {};
const rules = voiceRow.rules_json || {};
const alwaysRules = (rules.always_rules || []).join('; ');
const neverRules = (rules.never_rules || []).join('; ');
const bannedTerms = (rules.banned_terms || []).join(', ');

// Get top competitor concepts as style references
const videos = $('Fetch Competitor Videos').all().map(i => i.json).slice(0, 10);
const conceptExamples = [];
videos.forEach(v => {
  if (v.newConcepts) {
    const scriptMatch = v.newConcepts.match(/## SCRIPT\n([\s\S]{50,400}?)(?=\n# CONCEPT|$)/);
    if (scriptMatch) {
      conceptExamples.push(`[Style ref from @${v.creator}, ${Math.round(v.views/1000)}K views]:\n${scriptMatch[1].slice(0, 300)}`);
    }
  }
});
const styleContext = conceptExamples.slice(0, 3).join('\n\n') || 'No style references yet.';

const draftPrompt = `You are writing a complete, publish-ready ${channel} post for a brand.

CONTENT BRIEF:
Hook: ${brief.hook}
Opening: ${brief.opening}
Key points: ${(brief.body || []).join(' | ')}
CTA: ${brief.cta}
Hook type: ${brief.hook_type}

VOICE RULES:
ALWAYS: ${alwaysRules || 'Be direct, specific, value-first'}
NEVER: ${neverRules || 'Use jargon, hype, or vague claims'}
BANNED TERMS: ${bannedTerms || 'none'}

STYLE REFERENCES (proven formats from competitor analysis — adapt tone, NOT content):
${styleContext}

Write the complete ${channel} post. Requirements:
- Start with the exact hook from the brief (verbatim or sharper)
- Follow with the opening, then key points (each as its own short paragraph)
- End with the CTA
- Match voice rules strictly — flag any banned terms
- ${channel === 'LinkedIn' ? 'No hashtag spam. Max 3 relevant hashtags at the end.' : ''}
- ${channel === 'Email' ? 'Subject line first, then body.' : ''}
- ${channel === 'Blog' ? 'Include H2 subheadings. 400-600 words.' : 'Max 1200 characters for social.'}

Respond with JSON:
{
  "title": "short title",
  "draft_text": "complete post text",
  "char_count": number,
  "hook_used": "exact hook opening",
  "qa_flags": ["list any voice rule violations"]
}`;

return [{ json: {
  draftPrompt,
  brief_id: briefRow.id,
  channel,
  brand_id: $('Webhook').item.json.brand_id,
} }];

