parameters.jsCode:
const claudeResponse = $input.first().json;
const rawText = claudeResponse.content?.[0]?.text || '{}';

let draft;
try {
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  draft = JSON.parse(jsonMatch ? jsonMatch[0] : rawText);
} catch (e) {
  draft = { title: 'Draft', draft_text: rawText.slice(0, 2000), char_count: rawText.length, qa_flags: [] };
}

// QA scoring
const flags = Array.isArray(draft.qa_flags) ? draft.qa_flags.length : 0;
const hasHook = !!draft.hook_used;
const hasBody = draft.draft_text && draft.draft_text.length > 100;
const final_score = Math.max(50, 100 - (flags * 10) - (!hasHook ? 10 : 0) - (!hasBody ? 15 : 0));
const status = final_score >= 75 ? 'draft' : 'needs_revision';

const draftId = crypto.randomUUID();

return [{ json: {
  draft_id: draftId,
  draft,
  final_score,
  status,
  brief_id: $('Build Draft Prompt').item.json.brief_id,
  brand_id: $('Build Draft Prompt').item.json.brand_id,
  qa_json: { final_score, flags: draft.qa_flags || [], status },
} }];

